{{Infobox
| bodyclass  = vcard
| labelstyle = white-space:nowrap;
| bodystyle  = {{#if:{{{box_width|}}}|width:{{{box_width}}};}}
| above      = {{#if:{{{name|}}}|{{{name}}}|<includeonly>{{PAGENAMEBASE}}</includeonly>}}
| subheader  = {{#if:{{{native_artifact_name|{{{native_name|}}}}}}|<span class="nickname" {{#if:{{{native_name_lang|}}}| lang="{{{native_name_lang}}}"}}>{{{native_artifact_name|{{{native_name}}}}}}</span>}}
| image    = {{#invoke:InfoboxImage|InfoboxImage |image={{{image|}}} |size={{{image_size|}}} |sizedefault=frameless |upright=1 |alt={{{alt|}}} |suppressplaceholder=yes}}
| image2   = {{#invoke:InfoboxImage|InfoboxImage |image={{{image2|}}} |size={{{image2_size|}}} |sizedefault=frameless|upright=1 |alt={{{alt2|}}} |suppressplaceholder=yes}}
| caption  = {{{image_caption|{{{caption|}}}}}}
| caption2 = {{{image2_caption|{{{caption2|}}}}}}
<!--Descriptive data-->
| label1   = Type
| data1    = {{{type|}}}
| label2   = Material
| data2    = {{{material|}}}
| label3   = Size
| data3    = {{{size|}}}
| label4   = Long
