| label8   = Weight
| data8    = {{{weight|}}}
| label9   = Writing
| data9    = {{{writing|}}}
| label10   = Symbols
| data10    = {{{symbols|}}}
<!--Dates-->
| label11  = Created
| data11   = {{{created|}}}
| label12  = Period/culture
| data12   = {{{period|}}}
<!-- Discovery -->
| label13  = Discovered
| data13   = {{#if:{{{discovered|}}}|{{{discovered}}}| {{Br separated entries |{{{discovered_date|}}} |{{{discovered_place|}}} |{{{discovered_coords|}}} }} }}
| label14  = Discovered by
| data14   = {{{discovered_by|}}}
<!--Location created or found-->
| label15  = Place
| data15   = {{{place|}}}
